solution_code:
#include <concepts>
#include <cmath>
#include <iomanip>
#include <iostream>

template <typename T>
concept FloatingPoint = std::floating_point<T>;

auto my_sqrt(FloatingPoint auto x) {
    return std::sqrt(x);
}

int main() {
    double x;
    std::cin >> x;
    double result = my_sqrt(x);
    std::cout << "sqrt: " << std::fixed << std::setprecision(2) << result << "\n";
    return 0;
}

