solution_code:
#include <iostream>
#include <span>
#include <vector>

int sum_span(std::span<const int> data) {
    int total = 0;
    for (int x : data)
        total += x;
    return total;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];
    std::cout << "sum: " << sum_span(v) << "\n";
    return 0;
}
